import React, { useState } from 'react';
import { scannerAPI } from '../services/api';
import { toast } from 'react-toastify';
const ScannerPage = () => {
  const [text, setText] = useState('');
  const [result, setResult] = useState(null);
  const scan = async () => { if(!text.trim()) return; try{const r=await scannerAPI.scanText(text);setResult(r.data);toast.success('Analyzed!');}catch{toast.error('Failed');} };
  const s = {width:'100%',padding:'12px 16px',background:'rgba(255,255,255,0.05)',border:'1px solid rgba(255,255,255,0.1)',borderRadius:12,color:'#fff',outline:'none'};
  return <div style={{padding:24,maxWidth:800,margin:'0 auto'}}><h1 style={{fontSize:28,fontWeight:'bold',marginBottom:32}}>AI Scanner</h1>
    <div className='glass' style={{padding:24}}><h2 style={{marginBottom:16}}>Text Scanner</h2>
      <textarea value={text} onChange={e=>setText(e.target.value)} placeholder='e.g. Spent  at Starbucks' rows={3} style={{...s,resize:'none'}}/>
      <button onClick={scan} className='gradient-bg' style={{marginTop:16,padding:'12px 24px',border:'none',borderRadius:12,color:'#fff',fontWeight:600,cursor:'pointer'}}>Analyze</button>
      {result&&<div style={{marginTop:16,padding:16,background:'rgba(255,255,255,0.05)',borderRadius:12}}>
        <p>Amount: <b style={{color:'#22c55e'}}></b></p>
        <p>Category: <b style={{color:'#a855f7'}}>{result.ai_category} ({(result.confidence*100).toFixed(0)}%)</b></p>
        <p>Keywords: <span style={{color:'#60a5fa'}}>{result.matched_keywords?.join(', ')||'None'}</span></p>
      </div>}
    </div></div>;
};
export default ScannerPage;
